import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';

const CardInfoLeftBlock = () => {
  const { id } = useParams();
  const [tour, setTour] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/api/tours.json')
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        const foundTour = data.find(t => t.id === parseInt(id));
        setTour(foundTour);
        setLoading(false);
      })
      .catch(err => {
        console.error('❌ tours.json:', err);
        setLoading(false);
      });
  }, [id]);

  if (loading || !tour) {
    return (
      <div className="TVTourCardInfoLeftBlock">
        <div className="TVTourCardInfoFlights">
          <div className="TVTourFlightsListControl">
            <div className="TVTourFlightPreview" />
            <div className="TVTourFlightPreview" />
          </div>
        </div>
      </div>
    );
  }

  // Генерируем фейковые данные рейсов на основе тура
  const generateFlightData = () => {
    const departureTimes = ['09:55', '07:30', '14:25', '11:15'];
    const arrivalTimes = ['15:15', '12:45', '19:40', '16:30'];
    const durations = ['5 ч 20 м', '4 ч 15 м', '5 ч 45 м', '4 ч 50 м'];
    
    const outbound = {
      depTime: departureTimes[Math.floor(Math.random() * 4)],
      arrTime: arrivalTimes[Math.floor(Math.random() * 4)],
      date: tour.outboundDate,
      route: `${tour.departureCity} - ${tour.city}`,
      duration: durations[Math.floor(Math.random() * 4)],
      airline: tour.airline
    };

    const returnDate = new Date();
    returnDate.setDate(returnDate.getDate() + parseInt(tour.nights.split('-')[0]));
    const returnDay = returnDate.toLocaleDateString('ru', { day: 'numeric', month: 'short' });

    const returnFlight = {
      depTime: '16:20',
      arrTime: '21:05',
      date: returnDay,
      route: `${tour.city} - ${tour.departureCity}`,
      duration: '4 ч 45 м',
      airline: tour.airline
    };

    return { outbound, returnFlight };
  };

  const flights = generateFlightData();

  return (
    <>
      <div className="TVTourCardInfoLeftBlock">
        
        {/* CardOptions заглушка */}
        <div style={{ height: '60px', background: '#f8f9fa', marginBottom: '20px', borderRadius: '8px' }}>
          <div style={{ padding: '20px 15px', fontSize: '14px', color: '#666' }}>Опции тура</div>
        </div>

        {/* БЛОК РЕЙСОВ */}
        <div className="TVTourCardInfoFlights">
          <div className="TVTourFlightsListControl">
            
            {/* Превью рейсов */}
            <div className="TVTourFlightPreview" />
            <div className="TVTourFlightPreview" />

            <div className="TVTourFlightsList">
              
              {/* РЕЙС ТУДА */}
              <div className="TVTourFlightControl TVFontSize-M TVTextTransform-Uppercase TVGapSize-M">
                <div className="TVTourFlightIcon">✈️</div>
                
                <div className="TVTourFlightTimeBlock">
                  <div className="TVTourFlightTime">
                    <div>{flights.outbound.depTime}</div>
                    <div>{flights.outbound.arrTime}</div>
                  </div>
                  <div className="TVTourFlightDepartureDate">{flights.outbound.date}</div>
                </div>

                <div className="TVTourFlightPortBlock">
                  <div className="TVTourFlightPortNames">
                    {flights.outbound.route}
                  </div>
                  <div className="TVTourFlightConnectionBlock TVNonstop">
                    <div className="TVTourFlightDuration">{flights.outbound.duration}</div>
                  </div>
                </div>

                <div className="TVTourFlightAirlineBlock">
                  <div 
                    className="TVTourFlightAirline"
                    style={{
                      backgroundImage: `url('https://picsum.photos/40/30?random=${tour.id}')`,
                      backgroundSize: 'cover'
                    }}
                  />
                  <div>
                    <div className="TVTourFlightAirlineName TVOneAirline">
                      {tour.airline}
                    </div>
                    <div className="TVTourFlightType">Чартерный</div>
                  </div>
                </div>

                <div className="TVTourFlightInfo" />
              </div>

              {/* РЕЙС ОБРАТНО */}
              <div className="TVTourFlightControl TVTourFlightReverse TVFontSize-M TVTextTransform-Uppercase TVGapSize-M">
                <div className="TVTourFlightIcon">✈️</div>
                
                <div className="TVTourFlightTimeBlock">
                  <div className="TVTourFlightTime">
                    <div>{flights.returnFlight.depTime}</div>
                    <div>{flights.returnFlight.arrTime}</div>
                  </div>
                  <div className="TVTourFlightDepartureDate">{flights.returnFlight.date}</div>
                </div>

                <div className="TVTourFlightPortBlock">
                  <div className="TVTourFlightPortNames">
                    {flights.returnFlight.route}
                  </div>
                  <div className="TVTourFlightConnectionBlock TVNonstop">
                    <div className="TVTourFlightDuration">{flights.returnFlight.duration}</div>
                  </div>
                </div>

                <div className="TVTourFlightAirlineBlock">
                  <div 
                    className="TVTourFlightAirline"
                    style={{
                      backgroundImage: `url('https://picsum.photos/40/30?random=${tour.id + 1}')`,
                      backgroundSize: 'cover'
                    }}
                  />
                  <div>
                    <div className="TVTourFlightAirlineName TVOneAirline">
                      {tour.airline}
                    </div>
                    <div className="TVTourFlightType">Чартерный</div>
                  </div>
                </div>

                <div className="TVTourFlightInfo" />
              </div>
            </div>

            <div className="TVTourFlightMessage TVTourFlightDummy TVHide" />
            <div className="TVTourFlightMessage TVTourFlightUnknown TVHide" />
            <div className="TVTourFlightMoreButton" />
          </div>

          {/* ПРЕДУПРЕЖДЕНИЕ */}
          <div className="TVOrderWarningMessage">
            Внимание! В состав тура включен перелет регулярным авиарейсом.
            <br />
            <b>Цена не окончательная</b>, она может меняться в зависимости от тарифа авиакомпании.
            Отправьте запрос для уточнения стоимости тура.
          </div>
        </div>
      </div>

      {/* Точные стили Tourvisor */}
      <style dangerouslySetInnerHTML={{
        __html: `
          .TVTourCardInfoLeftBlock {
            padding: 20px 0;
          }
          
          .TVTourCardInfoFlights {
            background: white;
            border-radius: 12px;
            padding: 20px;
            border: 1px solid #e0e0e0;
            box-shadow: 0 2px 8px rgba(0,0,0,0.1);
          }
          
          .TVTourFlightsListControl {
            position: relative;
          }
          
          .TVTourFlightPreview {
            height: 8px;
            background: #f0f0f0;
            margin: 10px 0;
            border-radius: 4px;
          }
          
          .TVTourFlightsList {
            margin-top: 20px;
          }
          
          .TVTourFlightControl {
            display: flex;
            align-items: center;
            gap: 15px;
            padding: 15px 0;
            border-bottom: 1px solid #f0f0f0;
          }
          
          .TVTourFlightControl:last-child {
            border-bottom: none;
          }
          
          .TVTourFlightIcon {
            font-size: 20px;
          }
          
          .TVTourFlightTimeBlock {
            flex: 0 0 120px;
          }
          
          .TVTourFlightTime {
            display: flex;
            gap: 10px;
            font-weight: 600;
            font-size: 16px;
            color: #333;
          }
          
          .TVTourFlightDepartureDate {
            font-size: 14px;
            color: #666;
            margin-top: 4px;
          }
          
          .TVTourFlightPortBlock {
            flex: 1;
          }
          
          .TVTourFlightPortNames {
            font-size: 15px;
            font-weight: 500;
            color: #333;
            margin-bottom: 4px;
          }
          
          .TVTourFlightConnectionBlock {
            display: flex;
            align-items: center;
            gap: 8px;
          }
          
          .TVTourFlightDuration {
            font-size: 14px;
            color: #666;
          }
          
          .TVTourFlightAirlineBlock {
            display: flex;
            align-items: center;
            gap: 10px;
            flex: 0 0 200px;
          }
          
          .TVTourFlightAirline {
            width: 40px;
            height: 30px;
            border-radius: 4px;
            background-color: #f0f0f0;
          }
          
          .TVTourFlightAirlineName {
            font-size: 14px;
            font-weight: 500;
            color: #333;
          }
          
          .TVTourFlightType {
            font-size: 12px;
            color: #999;
          }
          
          .TVOrderWarningMessage {
            margin-top: 20px;
            padding: 15px;
            background: #fff3cd;
            border: 1px solid #ffeaa7;
            border-radius: 8px;
            font-size: 14px;
            color: #856404;
            line-height: 1.5;
          }
          
          @media (max-width: 768px) {
            .TVTourFlightControl {
              flex-direction: column;
              align-items: flex-start;
              gap: 10px;
            }
          }
        `
      }} />
    </>
  );
};

export default CardInfoLeftBlock;
